"use strict";let submitted=false;const QUIZ_KEYS=["quiz_clientele","quiz_volume","quiz_connexion","quiz_current_step"];function clearQuizSession(){QUIZ_KEYS.forEach(k=>sessionStorage.removeItem(k))}async function submitLead(payload){const resp=await fetch("/api/submit-lead",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(payload)});const data=await resp.json().catch(()=>({}));if(!resp.ok||!data.ok)throw new Error(`HTTP ${resp.status}`);return data.token}function showFormError(msg){const el=document.getElementById("form-error");if(!el)return;el.textContent=msg;el.classList.add("visible")}function clearFormError(){const el=document.getElementById("form-error");if(el){el.textContent="";el.classList.remove("visible")}}function initForm(){const form=document.getElementById("lead-form");const submitBtn=document.getElementById("submit-btn");const successEl=document.getElementById("form-success");if(!form)return;form.addEventListener("submit",async e=>{e.preventDefault();if(submitted)return;clearFormError();const firstName=document.getElementById("first-name")?.value.trim()||"";const email=document.getElementById("email")?.value.trim()||"";const gdpr=document.getElementById("gdpr")?.checked;if(!firstName){showFormError("Veuillez entrer votre prénom.");return}if(!email||!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)){showFormError("Veuillez entrer une adresse e-mail valide.");return}if(!gdpr){showFormError("Vous devez accepter la politique de confidentialité (RGPD) pour continuer.");return}submitBtn.disabled=true;submitBtn.textContent="Envoi en cours…";const payload={first_name:firstName,email:email,gdpr:gdpr,clientele:sessionStorage.getItem("quiz_clientele")||"",statut:"",volume:sessionStorage.getItem("quiz_volume")||"",connexion:sessionStorage.getItem("quiz_connexion")||""};try{const token=await submitLead(payload);submitted=true;clearQuizSession();if(successEl){successEl.textContent="✓ Merci ! Votre plan d'action vous a été envoyé par e-mail.";successEl.classList.add("show")}window.location.href=`/api/download-pdf?token=${encodeURIComponent(token)}`;setTimeout(()=>{window.location.href="index.html"},2500)}catch{submitBtn.disabled=false;submitBtn.textContent="Obtenir mon plan d'action (PDF)";showFormError("Une erreur est survenue. Veuillez réessayer dans quelques instants.")}})}function initB2CResult(){if(sessionStorage.getItem("quiz_clientele")!=="b2c")return;document.getElementById("results-banner-default")?.setAttribute("hidden","");document.getElementById("results-banner-b2c")?.removeAttribute("hidden");document.getElementById("b2c-message")?.removeAttribute("hidden");document.getElementById("partners-intro")?.setAttribute("hidden","");document.getElementById("articles-grid")?.setAttribute("hidden","")}async function loadAffiliateCatalog(){const resp=await fetch("content/affiliate-links.json");if(!resp.ok)throw new Error(`HTTP ${resp.status}`);return resp.json()}function buildCardHTML(entry){const ctaText=entry.ctaText||"Découvrir →";return`<div class="article-card partner-card" data-software="${entry.name}">\n              <span class="partner-badge">${entry.badge}</span>\n              <div class="article-header">\n                <img src="${entry.icon}" alt="" class="article-icon" aria-hidden="true" loading="lazy" />\n                <h3 class="article-title">${entry.name}</h3>\n              </div>\n              <p class="article-desc">${entry.desc}</p>\n              <a href="${entry.href}" class="btn-cta partner-discover-btn" target="_blank" rel="noopener sponsored">${ctaText}</a>\n            </div>`}function buildRecommendations(catalog){const grid=document.getElementById("articles-grid");if(!grid)return;const bucket=sessionStorage.getItem("quiz_volume");const entries=catalog[bucket];if(!Array.isArray(entries))return;grid.innerHTML=entries.map(buildCardHTML).join("")}async function init(){initB2CResult();initForm();if(!document.getElementById("articles-grid"))return;try{const catalog=await loadAffiliateCatalog();buildRecommendations(catalog)}catch{}}document.addEventListener("DOMContentLoaded",init);